package com.grit.liferecorder.data.local.entity
import androidx.room.*

@Entity(tableName="categories") data class CategoryEntity(@PrimaryKey(autoGenerate=true) val id:Long=0, val name:String, val colorKey:String, val isDefault:Boolean=false, val createdAt:Long, val updatedAt:Long)
@Entity(tableName="projects", foreignKeys=[ForeignKey(entity=CategoryEntity::class,parentColumns=["id"],childColumns=["categoryId"],onDelete=ForeignKey.SET_NULL)], indices=[Index("categoryId")]) data class ProjectEntity(@PrimaryKey(autoGenerate=true) val id:Long=0, val name:String, val description:String?=null, val categoryId:Long?=null, val isActive:Boolean=true, val createdAt:Long, val updatedAt:Long)
@Entity(tableName="tasks", indices=[Index("completeByDate"),Index("status"),Index("categoryId"),Index("projectId")]) data class TaskEntity(@PrimaryKey(autoGenerate=true) val id:Long=0, val title:String, val description:String?=null, val categoryId:Long?=null, val projectId:Long?=null, val completeByDate:String?=null, val reminderAt:Long?=null, val priority:String="Medium", val status:String="Open", val createdAt:Long, val updatedAt:Long, val completedAt:Long?=null, val canceledAt:Long?=null)
@Entity(tableName="tracked_actions", indices=[Index("defaultLabel"),Index("categoryId"),Index("projectId")]) data class TrackedActionEntity(@PrimaryKey(autoGenerate=true) val id:Long=0, val name:String, val description:String?=null, val defaultLabel:String="Neutral", val categoryId:Long?=null, val projectId:Long?=null, val scheduleHint:String?=null, val isActive:Boolean=true, val createdAt:Long, val updatedAt:Long)
@Entity(tableName="action_logs", foreignKeys=[ForeignKey(entity=TrackedActionEntity::class,parentColumns=["id"],childColumns=["trackedActionId"],onDelete=ForeignKey.CASCADE)], indices=[Index("trackedActionId"),Index("localDate"),Index("label")]) data class ActionLogEntity(@PrimaryKey(autoGenerate=true) val id:Long=0, val trackedActionId:Long, val localDate:String, val loggedAt:Long, val label:String, val note:String?=null, val createdAt:Long, val updatedAt:Long)
@Entity(tableName="routines", indices=[Index("categoryId"),Index("projectId")]) data class RoutineEntity(@PrimaryKey(autoGenerate=true) val id:Long=0, val name:String, val description:String?=null, val categoryId:Long?=null, val projectId:Long?=null, val scheduledDays:String, val scheduledTimeMinutes:Int?=null, val isActive:Boolean=true, val createdAt:Long, val updatedAt:Long)
@Entity(tableName="routine_steps", foreignKeys=[ForeignKey(entity=RoutineEntity::class,parentColumns=["id"],childColumns=["routineId"],onDelete=ForeignKey.CASCADE)], indices=[Index("routineId")]) data class RoutineStepEntity(@PrimaryKey(autoGenerate=true) val id:Long=0, val routineId:Long, val title:String, val stepOrder:Int, val isActive:Boolean=true, val createdAt:Long, val updatedAt:Long)
@Entity(tableName="routine_occurrences", foreignKeys=[ForeignKey(entity=RoutineEntity::class,parentColumns=["id"],childColumns=["routineId"],onDelete=ForeignKey.CASCADE)], indices=[Index("routineId"),Index("localDate"),Index(value=["routineId","localDate"], unique=true),Index("status")]) data class RoutineOccurrenceEntity(@PrimaryKey(autoGenerate=true) val id:Long=0, val routineId:Long, val localDate:String, val status:String="Scheduled", val startedAt:Long?=null, val completedAt:Long?=null, val skippedAt:Long?=null, val missedAt:Long?=null, val note:String?=null, val createdAt:Long, val updatedAt:Long)
@Entity(tableName="journal_entries", indices=[Index(value=["localDate"], unique=true),Index("categoryId"),Index("projectId")]) data class JournalEntryEntity(@PrimaryKey(autoGenerate=true) val id:Long=0, val localDate:String, val note:String?=null, val photoPath:String?=null, val categoryId:Long?=null, val projectId:Long?=null, val createdAt:Long, val updatedAt:Long)
